import { render, fireEvent } from '@testing-library/react-native';
import React from 'react';

import { TestProvider } from '../../__mocks__/utils/test-provider';
import Input from '../../../src/atomic/atoms/Input';
import colors from '../../../src/atomic/constants/colors';

jest.mock('../../../src/redux/actions/pciActions', () => ({
  getPCI: jest.fn(c => ({ type: 'GET_PCI', payload: c })),
}));

describe('Input Component', () => {
  const baseProps = {
    label: 'Test Label',
    accessibilityLabel: 'test-input',
    type: 'text',
    onChangeText: jest.fn(),
    placeholder: 'Enter text',
  };

  it('renders correctly with default props', () => {
    const { getByTestId } = render(
      <TestProvider>
        <Input {...baseProps} />
      </TestProvider>,
    );
    expect(getByTestId('input-component')).toBeTruthy();
  });

  it('displays error styling when error is true', () => {
    const { getByTestId } = render(
      <TestProvider>
        <Input {...baseProps} error testID="input-field" />
      </TestProvider>,
    );

    const input = getByTestId('input-field');
    expect(input.props.placeholderTextColor).toBe(colors.red);
  });

  it('displays label when value is not empty', () => {
    const { getByText } = render(
      <TestProvider>
        <Input {...baseProps} value="test" />
      </TestProvider>,
    );

    expect(getByText('Test Label')).toBeTruthy();
  });

  it('dispatches PCI action for credit card input', () => {
    const value = '4111111111111111';

    render(
      <TestProvider>
        <Input {...baseProps} type="credit-card" value={value} isPci />
      </TestProvider>,
    );
  });

  it('shows icon when provided', () => {
    const { getByTestId } = render(
      <TestProvider>
        <Input
          {...baseProps}
          icon="test-icon"
          value="test"
          testID="icon-button"
        />
      </TestProvider>,
    );

    expect(getByTestId('icon-button')).toBeTruthy();
  });

  it('handles text input changes', () => {
    const { getByTestId } = render(
      <TestProvider>
        <Input {...baseProps} testID="input-field" />
      </TestProvider>,
    );

    const input = getByTestId('input-field');
    fireEvent.changeText(input, 'new text');
    expect(baseProps.onChangeText).toHaveBeenCalledWith('new text');
  });

  it('applies greenishBlue color when showGreenishBlue is true', () => {
    render(
      <TestProvider>
        <Input {...baseProps} showGreenishBlue testID="input-field" />
      </TestProvider>,
    );
  });

  it('renders correctly when disabled', () => {
    const { getByTestId } = render(
      <TestProvider>
        <Input {...baseProps} editable={false} testID="input-field" />
      </TestProvider>,
    );

    expect(getByTestId('input-field').props.editable).toBe(false);
  });
});

