import React from 'react';
import { render, fireEvent } from '@testing-library/react-native';
import { NavigationContainer } from '@react-navigation/native';

import ButtonFinancialPoints from '../../../../src/atomic/molecules/ButtonFinancialPoints/index';
import { ThemeProvider } from 'styled-components/native';
import theme from '../../../../src/styles/theme';

jest.mock('~/routes/navigation', () => ({
  navigate: jest.fn(),
}));

jest.mock('@semparar/design-system-app', () => {
  const { Text, TouchableOpacity, View } = jest.requireActual('react-native');
  return {
    CardActivity: ({ children, onPress, description, testID, ...props }: {
      children?: React.ReactNode;
      onPress?: () => void;
      description?: string | React.ReactNode;
      testID?: string;
      [key: string]: unknown;
    }) => (
      <TouchableOpacity testID={testID || 'mock-card-activity'} {...props} onPress={onPress}>
        <View>
          {description && (
            <View>
              {typeof description === 'string' ? <Text>{description}</Text> : description}
            </View>
          )}
          {children}
        </View>
      </TouchableOpacity>
    ),
    Text: ({ children, ...props }: { children?: React.ReactNode;[key: string]: unknown }) => (
      <Text {...props}>{children}</Text>
    ),
  };
});

const renderWithNavigation = (component: React.JSX.Element) => {
  return render(
    <NavigationContainer>
      <ThemeProvider theme={theme}>{component}</ThemeProvider>
    </NavigationContainer>
  );
};

describe('ButtonFinancialPoints', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('deve passar as props corretas para o ButtonFinancialPointsView', () => {
    const onPressMock = jest.fn();
    const onPressCashbackRescueMock = jest.fn();

    const {
      getByText,
      getByTestId,
    } = renderWithNavigation(
      <ButtonFinancialPoints
        points={0}
        onPress={onPressMock}
        onPressCashbackRescue={onPressCashbackRescueMock}
        rewardEnabled={false}
        cashbackValue={100}
      />
    );

    expect(getByTestId('btn-financial-points-disabled')).toBeTruthy();
    expect(getByText(/R\$\s*100,00/)).toBeTruthy();
  });

  it('deve chamar onPress quando o botão for pressionado', () => {
    const onPressMock = jest.fn();
    const onPressCashbackRescueMock = jest.fn();

    const { getByTestId } = renderWithNavigation(
      <ButtonFinancialPoints
        points={10}
        onPress={onPressMock}
        onPressCashbackRescue={onPressCashbackRescueMock}
        rewardEnabled={true}
        cashbackValue={50}
      />
    );

    const button = getByTestId('btn-financial-points-with-balance');
    fireEvent.press(button);

    expect(onPressMock).toHaveBeenCalled();
  });

  it('deve chamar onPressCashbackRescue quando o botão for pressionado e rewardEnabled for false', () => {
    const onPressMock = jest.fn();
    const onPressCashbackRescueMock = jest.fn();

    const { getByTestId } = renderWithNavigation(
      <ButtonFinancialPoints
        points={0}
        onPress={onPressMock}
        onPressCashbackRescue={onPressCashbackRescueMock}
        rewardEnabled={false}
        cashbackValue={0}
      />
    );

    const button = getByTestId('btn-financial-points-disabled');
    fireEvent.press(button);

    expect(onPressCashbackRescueMock).toHaveBeenCalled();
  });
});

