import React from 'react';
import { render } from '../../../util';
import LivenessErrorView from '../../../../src/atomic/organisms/LivenessError/view';
import { LivenessErrorViewProps } from '../../../../src/atomic/organisms/LivenessError/Models';

jest.mock('../../../../src/atomic/molecules/TipsList', () => {
  const React = require('react');
  const { Text } = require('react-native');

  return {
    TipsList: ({ items }: any) => (
      <>
        {items.map((item: any) => (
          <Text key={item.text}>{item.text}</Text>
        ))}
      </>
    ),
  };
});

describe('LivenessErrorView - Snapshot', () => {
  const mockOnPress = jest.fn();

  const renderComponent = (type: LivenessErrorViewProps['type']) => {
    const props: LivenessErrorViewProps = {
      type,
      onPress: mockOnPress,
    };
    return render(<LivenessErrorView {...props} />);
  };

  it('should match snapshot when type is "error"', () => {
    const screen = renderComponent('error');
    expect(screen.toJSON()).toMatchSnapshot();
  });

  it('should match snapshot when type is "attempt"', () => {
    const screen = renderComponent('attempt');
    expect(screen.toJSON()).toMatchSnapshot();
  });
});

