import { PropsIconsNameCore } from '@semparar/design-system-app';
import { act } from '@testing-library/react-hooks';
import React from 'react';

import CashbackCellDropdown from '../../../../src/atomic/organisms/CashbackCellDropdown';
import {
  CashbackCellDropdownProps,
  CashbackCellDropdownViewProps,
} from '../../../../src/atomic/organisms/CashbackCellDropdown/Models';
import CashbackCellDropdownView from '../../../../src/atomic/organisms/CashbackCellDropdown/view';
import { render } from '../../../util';

jest.useFakeTimers();

jest.mock('../../../../src/atomic/organisms/CashbackCellDropdown/view', () => {
  const actual = jest.requireActual(
    '../../../../src/atomic/organisms/CashbackCellDropdown/view',
  );

  const react = jest.requireActual('react');

  return jest.fn(props => {
    return react.createElement(actual.default || actual, props);
  });
});

describe('CashbackCellDropdown', () => {
  const getProps = () => {
    const mockOnScroll = jest.fn();

    return {
      parent: {
        value: '100',
        title: 'Cashback',
        iconColor: 'BRAND_COMPLEMENT_02',
        icon: 'icon-default' as PropsIconsNameCore,
      },
      cashbackData: [
        {
          date: '2024-02-01',
          items: [
            {
              id: 1,
              title: 'Purchase 1',
              description: 'Online payment',
              percentage: '10',
              cashback: 5,
              value: 'R$ 50,00',
              resgate: false,
              type: 'credit',
              icon: 'icon-default' as PropsIconsNameCore,
              iconColor: 'GREEN',
              titleColor: 'BLACK',
              descriptionColor: 'GRAY',
              valueColor: 'BLUE',
              hour: '12:30',
              hourColor: 'GRAY',
              onPress: jest.fn(),
            },
          ],
        },
      ],
      isAvailableCashback: true,
      onScroll: mockOnScroll,
    } satisfies CashbackCellDropdownProps;
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should render the component correctly', () => {
    const screen = render(<CashbackCellDropdown {...getProps()} />);
    expect(screen.toJSON()).toMatchSnapshot();
  });

  test('onScroll', () => {
    const gotProps = getProps();

    let viewProps!: CashbackCellDropdownViewProps;
    const mockView = (CashbackCellDropdownView as jest.Mock).mockImplementation(
      props => {
        viewProps = props;
        return null;
      },
    );

    render(<CashbackCellDropdown {...gotProps} />);

    act(() => {
      viewProps.handleDropdown();
    });

    jest.runAllTimers();

    expect(gotProps.onScroll).toHaveBeenCalled();

    mockView.mockReset();
  });
});

