import { PropsIconsNameCore } from '@semparar/design-system-app';
import React from 'react';

import { TestProvider } from '../../../__mocks__/utils/test-provider';
import { CashbackCellDropdownViewProps } from '../../../../src/atomic/organisms/CashbackCellDropdown/Models';
import CashbackCellDropdownView from '../../../../src/atomic/organisms/CashbackCellDropdown/view';
import { render } from '../../../util';

describe('CashbackCellDropdownView', () => {
  const mockHandleDropdown = jest.fn();

  const defaultProps: CashbackCellDropdownViewProps = {
    isOpen: false,
    parent: {
      value: '100',
      title: 'Cashback',
      iconColor: 'BRAND_COMPLEMENT_02',
      icon: 'ICON_CASHBACK' as PropsIconsNameCore,
    },
    handleDropdown: mockHandleDropdown,
    isAvailableCashback: true,
    formattedItems: undefined,
  };

  it('should render the component correctly', () => {
    const screen = render(<CashbackCellDropdownView {...defaultProps} />);
    expect(screen.toJSON()).toMatchSnapshot();
  });

  it('should show cashback history when isOpen is true', () => {
    const { getByText } = render(
      <TestProvider>
        <CashbackCellDropdownView {...defaultProps} isOpen />
      </TestProvider>,
    );
    expect(
      getByText('Seu histórico de cashback é mantido somente por 60 dias.'),
    ).toBeTruthy();
  });

  it('should not display cashback history message if isAvailableCashback is false', () => {
    const { queryByText } = render(
      <TestProvider>
        <CashbackCellDropdownView
          {...defaultProps}
          isOpen
          isAvailableCashback={false}
        />
      </TestProvider>,
    );
    expect(
      queryByText('Seu histórico de cashback é mantido somente por 60 dias.'),
    ).toBeNull();
  });
});

