import React from 'react';
import { render } from '../../../util';
import BasicPageView from '../../../../src/atomic/templates/BasicPage/view';
import { Text } from '@semparar/design-system-app';
import {
  ScrollViewContainer,
  Container,
  Header,
  ContainerHeader,
  Title,
} from '../../../../src/atomic/templates/BasicPage/styles';

describe('BasicPageView', () => {
  it('should render children and title if provided', () => {
    const { getByText } = render(
      <BasicPageView
        bgColor="white"
        headerProps={{}}
        scrollViewProps={{}}
        titleProps={{ text: 'Test Title' }}
      >
        <>{<Text>Child content</Text>}</>
      </BasicPageView>
    );

    expect(getByText('Test Title')).toBeTruthy();
    expect(getByText('Child content')).toBeTruthy();
  });

  it('should not render title if titleProps is undefined', () => {
    const { queryByTestId } = render(
      <BasicPageView
        bgColor="white"
        headerProps={{}}
        scrollViewProps={{}}
      >
        <>{<Text>Only Child</Text>}</>
      </BasicPageView>
    );

    expect(queryByTestId('title')).toBeNull(); // Se quiser adicionar testID no <Title>
  });
  it('should render Container with custom background color', () => {
    const screen = render(<Container bgColor="#123456" testID="container" />);
    expect(screen.getByTestId('container')).toHaveStyle({ backgroundColor: '#123456' });
  });
  it('should render Title with text', () => {
    const screen = render(<Title>Teste de Título</Title>);
    expect(screen.getByText('Teste de Título')).toBeTruthy();
  });
  it('should render Header with given title', () => {
    const screen = render(<Header title="Título do Header" />);
    expect(screen.getByText('Título do Header')).toBeTruthy();
  });
  it('should render ContainerHeader', () => {
    const screen = render(<ContainerHeader testID="container-header" />);
    expect(screen.getByTestId('container-header')).toBeTruthy();
  });
  it('should render ScrollViewContainer', () => {
    const screen = render(<ScrollViewContainer bgColor="#abcdef" testID="scroll-container" />);
    expect(screen.getByTestId('scroll-container')).toBeTruthy();
  });

  it('should render ScrollViewContainer with default background color when no bgColor is provided', () => {
    const { getByTestId } = render(<ScrollViewContainer testID="scroll-default" />);
    const scroll = getByTestId('scroll-default');

    expect(scroll.props.contentContainerStyle.backgroundColor).toBe('#F4F7F7');
    // Remover essa linha abaixo, pois pode ser inconsistente:
    // expect(scroll.props.style.backgroundColor).toBe('#F4F7F7');
  });

});

