import { PropsItemsTransactionsList } from '@semparar/design-system-app/src/atomic/fintech/TransactionsList/Models';
import { render } from '@testing-library/react-native';
import React from 'react';

import TransactionsListFactory from '../../../src/components/TransactionsListFactory';
import { DataGroupedByDayMapper } from '../../../src/components/TransactionsListFactory/mappers';

jest.mock('@semparar/design-system-app', () => {
  const React = require('react');
  const { View } = require('react-native');
  const libs = jest.requireActual('@semparar/design-system-app');

  return {
    ...libs,
    ListCardTransition: ({ testID, items }: { testID: string; items: any }) => (
      <View testID={testID}>{JSON.stringify(items)}</View>
    ),
  };
});

jest.mock(
  'src/components/TransactionsListFactory/TransactionsListOld/index.tsx',
  () => {
    const React = require('react');
    const { View } = require('react-native');
    return (props: any) => (
      <View testID="transactions-list-old">{JSON.stringify(props)}</View>
    );
  },
);

jest.mock('src/components/TransactionsListFactory/mappers.ts', () => ({
  DataGroupedByDayMapper: {
    map: jest.fn(data =>
      data ? data.map((item: any) => ({ ...item, mapped: true })) : [],
    ),
  },
}));

describe('TransactionsListFactory', () => {
  const mockData: PropsItemsTransactionsList[] = [
    {
      date: '2024-02-18',
      dateColor: '#000',
      items: [
        {
          id: 1,
          icon: 'icon-card-plus',
          iconColor: '#FF0000',
          title: 'Compra no Mercado',
          titleColor: '#000',
          value: '-R$ 150,00',
          valueColor: '#FF0000',
          hour: '14:30',
          hourColor: '#555',
          description: 'Pagamento efetuado com sucesso',
          descriptionColor: '#777',
          bgColor: '#FFF',
          type: 'payment',
        },
      ],
    },
  ];

  test('renderiza TransactionsListLoading quando isLoading é true', () => {
    const { getByTestId } = render(
      <TransactionsListFactory isLoading homeLatestActivities={false} />,
    );
    expect(getByTestId('transactions-list-loading')).toBeTruthy();
  });

  test('renderiza ListCardTransition quando homeLatestActivities é true e isLoading é false', () => {
    (DataGroupedByDayMapper.map as jest.Mock).mockReturnValue(
      mockData.map(item => ({ ...item, mapped: true })),
    );

    const { getByTestId } = render(
      <TransactionsListFactory
        isLoading={false}
        homeLatestActivities
        dataGroupedByDay={mockData}
      />,
    );

    const listCard = getByTestId('list-card-transition-test-id');
    expect(listCard).toBeTruthy();
    expect(listCard.children[0]).toEqual(
      JSON.stringify(mockData.map(item => ({ ...item, mapped: true }))),
    );
  });

  test('renderiza TransactionsListOld quando homeLatestActivities é false', () => {
    const { getByTestId } = render(
      <TransactionsListFactory
        isLoading={false}
        homeLatestActivities={false}
        isActivitiesError
        dataGroupedByDay={mockData}
      />,
    );

    const transactionsOld = getByTestId('transactions-list-old');
    expect(transactionsOld).toBeTruthy();
    expect(transactionsOld.props.children).toContain(
      '"isActivitiesError":true',
    );
    expect(transactionsOld.props.children).toContain(JSON.stringify(mockData));
  });
});

