import * as navigation from '@react-navigation/native';
import { renderHook } from '@testing-library/react-hooks';
import { NativeModules, NativeEventEmitter } from 'react-native';

import { UnicoCredentials } from '../../../../src/hooks/custom/Models';
import { useUnicoNativeModule } from '../../../../src/hooks/custom/useUnicoNativeModule';

jest.mock('react-native', () => {
  const actualReactNative = jest.requireActual('react-native');

  return {
    ...actualReactNative,
    NativeModules: {
      BridgeConfig: {
        setConfig: jest.fn(),
      },
      UnicoCheckModule: {},
    },
    NativeEventEmitter: jest.fn(),
  };
});

describe('useUnicoNativeModule', () => {
  let setConfigMock: jest.Mock;
  let addListenerMock: jest.Mock;
  let removeAllListenersMock: jest.Mock;
  let eventEmitterInstance: Record<string, jest.Mock>;
  let cleanupFn: (() => void) | undefined;

  beforeEach(() => {
    jest.clearAllMocks();

    setConfigMock = NativeModules.BridgeConfig.setConfig;
    removeAllListenersMock = jest.fn();
    addListenerMock = jest.fn(() => ({
      remove: jest.fn(),
    }));

    eventEmitterInstance = {
      addListener: addListenerMock,
      removeAllListeners: removeAllListenersMock,
    };

    (NativeEventEmitter as jest.Mock).mockImplementation(
      () => eventEmitterInstance,
    );

    cleanupFn = undefined;
    (navigation.useFocusEffect as jest.Mock).mockImplementation(effect => {
      cleanupFn = effect();
      return cleanupFn;
    });
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  it('deve chamar setConfig com as credenciais fornecidas e retornar o módulo nativo e o event emitter', () => {
    const credentials = { user: 'teste', token: '123' };
    const callbacks = {};
    const { result } = renderHook(() =>
      useUnicoNativeModule(
        callbacks,
        credentials as unknown as UnicoCredentials,
      ),
    );

    expect(setConfigMock).toHaveBeenCalledWith(credentials);
    expect(result.current.unicoCheckModule).toBe(
      NativeModules.UnicoCheckModule,
    );
    expect(result.current.UnicoEventEmitter).toBe(eventEmitterInstance);
  });

  it('deve adicionar os listeners para os callbacks informados', () => {
    const credentials = { user: 'teste', token: '123' };
    const onError = jest.fn();
    const onSuccess = jest.fn();
    const onSuccessJWT = jest.fn();
    const callbacks = { onError, onSuccess, onSuccessJWT };

    renderHook(() =>
      useUnicoNativeModule(
        callbacks,
        credentials as unknown as UnicoCredentials,
      ),
    );

    expect(addListenerMock).toHaveBeenCalledTimes(3);
    expect(addListenerMock).toHaveBeenCalledWith('onError', onError);
    expect(addListenerMock).toHaveBeenCalledWith('onSuccess', onSuccess);
    expect(addListenerMock).toHaveBeenCalledWith('onSuccessJWT', onSuccessJWT);
  });

  it('não deve adicionar listeners se os callbacks não forem informados', () => {
    const credentials = { user: 'teste', token: '123' };
    const callbacks = {};

    renderHook(() =>
      useUnicoNativeModule(
        callbacks,
        credentials as unknown as UnicoCredentials,
      ),
    );

    expect(addListenerMock).not.toHaveBeenCalled();
  });

  it('deve adicionar apenas o listener do onError quando somente onError for informado', () => {
    const credentials = { user: 'teste', token: '123' };
    const onError = jest.fn();
    const callbacks = { onError };

    renderHook(() =>
      useUnicoNativeModule(
        callbacks,
        credentials as unknown as UnicoCredentials,
      ),
    );

    expect(addListenerMock).toHaveBeenCalledTimes(1);
    expect(addListenerMock).toHaveBeenCalledWith('onError', onError);
  });

  it('deve remover os listeners quando o hook for desmontado', () => {
    const credentials = { user: 'teste', token: '123' };
    const onError = jest.fn();
    const onSuccess = jest.fn();
    const onSuccessJWT = jest.fn();
    const callbacks = { onError, onSuccess, onSuccessJWT };

    const { unmount } = renderHook(() =>
      useUnicoNativeModule(
        callbacks,
        credentials as unknown as UnicoCredentials,
      ),
    );

    unmount();
    if (cleanupFn) cleanupFn();

    expect(addListenerMock).toHaveBeenCalledTimes(3);
    expect(addListenerMock).toHaveBeenCalledWith('onError', onError);
    expect(addListenerMock).toHaveBeenCalledWith('onSuccess', onSuccess);
    expect(addListenerMock).toHaveBeenCalledWith('onSuccessJWT', onSuccessJWT);

    expect(removeAllListenersMock).toHaveBeenCalledTimes(3);
    expect(removeAllListenersMock).toHaveBeenCalledWith('onError');
    expect(removeAllListenersMock).toHaveBeenCalledWith('onSuccess');
    expect(removeAllListenersMock).toHaveBeenCalledWith('onSuccessJWT');
  });
});

