import { renderHook, act } from '@testing-library/react-hooks';
import { AxiosError, AxiosResponse } from 'axios';

import { useAxios } from '../../../src/hooks/useAxios';

jest.mock('react-native-blob-util', () => {
  const mockConfig = jest.fn(() => ({
    fetch: jest.fn(() =>
      Promise.resolve({
        path: () => '/mocked/path/to/image.png',
      }),
    ),
    session: jest.fn(() => ({
      fetch: jest.fn(() =>
        Promise.resolve({
          path: () => '/mocked/path/to/image.png',
        }),
      ),
    })),
  }));

  return {
    __esModule: true,
    default: {
      config: mockConfig,
      fetch: jest.fn(() =>
        Promise.resolve({
          path: () => '/mocked/path/to/image.png',
        }),
      ),
      wrap: jest.fn(),
      session: jest.fn(() => ({
        fetch: jest.fn(() =>
          Promise.resolve({
            path: () => '/mocked/path/to/image.png',
          }),
        ),
      })),
    },
    fs: {
      dirs: {
        DocumentDir: '/mocked/path',
      },
      exists: jest.fn(() => Promise.resolve(true)),
      unlink: jest.fn(() => Promise.resolve()),
    },
  };
});

const mockAxiosError = new AxiosError('Erro de API');
const mockSuccessResponse: AxiosResponse<{ message: string }> = {
  data: { message: 'Sucesso' },
  status: 200,
  statusText: 'OK',
  headers: {},
  config: {},
};

mockAxiosError.response = {
  data: 'Erro no servidor',
} as AxiosError['response'];

describe('useAxios Hook', () => {
  it('must start with correct initial state', () => {
    const requestMock = jest.fn();
    const { result } = renderHook(() => useAxios(requestMock));

    expect(result.current.response).toBeUndefined();
    expect(result.current.error).toBe('');
    expect(result.current.isLoading).toBe(false);
    expect(result.current.hasError).toBe(false);
  });

  it('must set isLoading to true when initiating the request', async () => {
    const requestMock = jest.fn(() => Promise.resolve(mockSuccessResponse));
    const { result } = renderHook(() => useAxios(requestMock));

    act(() => {
      result.current.makeRequest();
    });

    expect(result.current.isLoading).toBe(true);
  });

  it('must store the response correctly when the request is successful', async () => {
    const requestMock = jest.fn(() => Promise.resolve(mockSuccessResponse));
    const { result, waitForNextUpdate } = renderHook(() =>
      useAxios(requestMock),
    );

    act(() => {
      result.current.makeRequest();
    });

    await waitForNextUpdate();

    expect(result.current.response).toEqual({ message: 'Sucesso' });
    expect(result.current.error).toBe('');
    expect(result.current.hasError).toBe(false);
    expect(result.current.isLoading).toBe(false);
  });

  it('should store the error correctly when the request fails with an Axios error', async () => {
    const requestMock = jest.fn(() => Promise.reject(mockAxiosError));
    const { result, waitForNextUpdate } = renderHook(() =>
      useAxios(requestMock),
    );

    act(() => {
      result.current.makeRequest();
    });

    await waitForNextUpdate();

    expect(result.current.error).toBe('Erro no servidor');
    expect(result.current.hasError).toBe(true);
    expect(result.current.isLoading).toBe(false);
  });

  it('should store "Unknown error" when an Axios error does not contain response.data', async () => {
    const mockAxiosErrorWithoutData = new AxiosError('Erro de API');
    mockAxiosErrorWithoutData.response = {
      data: undefined,
    } as AxiosError['response'];

    const requestMock = jest.fn(() =>
      Promise.reject(mockAxiosErrorWithoutData),
    );
    const { result, waitForNextUpdate } = renderHook(() =>
      useAxios(requestMock),
    );

    act(() => {
      result.current.makeRequest();
    });

    await waitForNextUpdate();

    expect(result.current.error).toBe('Erro desconhecido');
    expect(result.current.hasError).toBe(true);
    expect(result.current.isLoading).toBe(false);
  });

  it('should store "Unknown error" when an unknown error occurs', async () => {
    const requestMock = jest.fn(() => Promise.reject(new Error()));
    const { result, waitForNextUpdate } = renderHook(() =>
      useAxios(requestMock),
    );

    act(() => {
      result.current.makeRequest();
    });

    await waitForNextUpdate();

    expect(result.current.error).toBe('Erro desconhecido');
    expect(result.current.hasError).toBe(true);
    expect(result.current.isLoading).toBe(false);
  });
});

