import { renderHook } from '@testing-library/react-hooks';
import { Alert, Linking, Platform } from 'react-native';
import { PERMISSIONS, check, request } from 'react-native-permissions';

import { useCameraPermission } from '../../../src/hooks/useCameraPermission';

Alert.alert = jest.fn();
Linking.openSettings = jest.fn();

jest.mock('react-native-permissions', () => ({
  PERMISSIONS: {
    ANDROID: { CAMERA: 'android.permission.CAMERA' },
    IOS: { CAMERA: 'ios.permission.CAMERA' },
  },
  check: jest.fn(),
  request: jest.fn(),
}));

describe('useCameraPermission Hook', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should request camera permission on Android when blocked', async () => {
    Platform.OS = 'android';
    (request as jest.Mock).mockResolvedValue('blocked');

    const { result } = renderHook(() => useCameraPermission());
    await result.current.requestCameraPermission();

    expect(Alert.alert).toHaveBeenCalledWith(
      'Permissão Necessária',
      'Conceda acesso à câmera nas configurações do seu telefone.',
      [
        { text: 'Abrir Configurações', onPress: expect.any(Function) },
        { text: 'OK' },
      ],
      { cancelable: false },
    );
  });

  it('should request permission on iOS when denied and not blocked', async () => {
    Platform.OS = 'ios';
    (check as jest.Mock).mockResolvedValue('denied');
    (request as jest.Mock).mockResolvedValue('granted');

    const { result } = renderHook(() => useCameraPermission());
    await result.current.requestCameraPermission();

    expect(check).toHaveBeenCalledWith(PERMISSIONS.IOS.CAMERA);
    expect(request).toHaveBeenCalledWith(PERMISSIONS.IOS.CAMERA);
  });

  it('should show an alert and open settings when permission is blocked on iOS', async () => {
    Platform.OS = 'ios';
    (check as jest.Mock).mockResolvedValue('blocked');

    const { result } = renderHook(() => useCameraPermission());
    await result.current.requestCameraPermission();

    expect(Alert.alert).toHaveBeenCalledWith(
      'Permissão Necessária',
      'Conceda acesso à "Câmera e Movimento" nas configurações do seu telefone.',
      [
        { text: 'Abrir Configurações', onPress: expect.any(Function) },
        { text: 'OK' },
      ],
      { cancelable: false },
    );

    const alertCallback = (Alert.alert as jest.Mock).mock.calls[0][2][0]
      .onPress;
    alertCallback();
    expect(Linking.openSettings).toHaveBeenCalled();
  });
  it('should check and request MOTION permission on iOS when denied', async () => {
    Platform.OS = 'ios';
    (check as jest.Mock).mockImplementation(permission => {
      if (permission === PERMISSIONS.IOS.CAMERA)
        return Promise.resolve('granted');
      if (permission === PERMISSIONS.IOS.MOTION)
        return Promise.resolve('denied');
    });

    (request as jest.Mock).mockImplementation(permission => {
      if (permission === PERMISSIONS.IOS.MOTION)
        return Promise.resolve('granted');
    });

    const { result } = renderHook(() => useCameraPermission());
    await result.current.requestCameraPermission();

    expect(check).toHaveBeenCalledWith(PERMISSIONS.IOS.CAMERA);
    expect(check).toHaveBeenCalledWith(PERMISSIONS.IOS.MOTION);
    expect(request).toHaveBeenCalledWith(PERMISSIONS.IOS.MOTION);
  });
  it('should not request permission if already granted', async () => {
    Platform.OS = 'ios';
    (check as jest.Mock).mockResolvedValue('granted');

    const { result } = renderHook(() => useCameraPermission());
    await result.current.requestCameraPermission();

    expect(request).not.toHaveBeenCalled();
    expect(Alert.alert).not.toHaveBeenCalled();
  });

  it('should return without triggering alert when Android permission is granted or denied', async () => {
    Platform.OS = 'android';

    (request as jest.Mock).mockResolvedValueOnce('granted');
    const { result } = renderHook(() => useCameraPermission());
    await result.current.requestCameraPermission();

    (request as jest.Mock).mockResolvedValueOnce('denied');
    await result.current.requestCameraPermission();

    expect(Alert.alert).not.toHaveBeenCalled();
    expect(Linking.openSettings).not.toHaveBeenCalled();
  });
});

