import { renderHook, act } from '@testing-library/react-hooks';
import { usePreventDoubleClick } from '../../../src/hooks/usePreventDoubleClick';

describe('usePreventDoubleClick', () => {
  const mockCallback = jest.fn();
  const mockOnDoubleClickAttempt = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
    jest.useFakeTimers();
  });

  afterEach(() => {
    jest.useRealTimers();
  });

  describe('Prevent double click within 1000ms (1 second) by default', () => {
    it('should prevent double click within 1000ms (1 second) by default', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, {
          onDoubleClickAttempt: mockOnDoubleClickAttempt,
        }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);
      expect(mockOnDoubleClickAttempt).toHaveBeenCalledTimes(1);
      expect(result.current.isProcessing).toBe(true);
    });

    it('should prevent double click within custom delay period', async () => {
      const customDelay = 500;
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, {
          delay: customDelay,
          onDoubleClickAttempt: mockOnDoubleClickAttempt,
        }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);
      expect(mockOnDoubleClickAttempt).toHaveBeenCalledTimes(1);
    });

    it('should allow second execution after delay period', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, {
          delay: 1000,
          onDoubleClickAttempt: mockOnDoubleClickAttempt,
        }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      act(() => {
        jest.advanceTimersByTime(1100);
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(2);
      expect(mockOnDoubleClickAttempt).toHaveBeenCalledTimes(0);
    });

    it('should handle multiple rapid executions correctly', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, {
          delay: 1000,
          onDoubleClickAttempt: mockOnDoubleClickAttempt,
        }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
        await result.current.executeWithPreventDoubleClick();
        await result.current.executeWithPreventDoubleClick();
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);

      expect(mockOnDoubleClickAttempt).toHaveBeenCalledTimes(3);
    });
  });

  describe('Estado isProcessing', () => {
    it('should set isProcessing to true during execution', async () => {
      const { result } = renderHook(() => usePreventDoubleClick(mockCallback));

      expect(result.current.isProcessing).toBe(false);

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(result.current.isProcessing).toBe(true);
    });

    it('should prevent execution when isProcessing is true', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, {
          onDoubleClickAttempt: mockOnDoubleClickAttempt,
        }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(result.current.isProcessing).toBe(true);

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);
      expect(mockOnDoubleClickAttempt).toHaveBeenCalledTimes(1);
    });

    it('should reset isProcessing after delay period', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, { delay: 1000 }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(result.current.isProcessing).toBe(true);

      act(() => {
        jest.advanceTimersByTime(1100);
      });

      expect(result.current.isProcessing).toBe(false);
    });
  });

  describe('Reset function', () => {
    it('should reset isProcessing to false', async () => {
      const { result } = renderHook(() => usePreventDoubleClick(mockCallback));

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(result.current.isProcessing).toBe(true);

      act(() => {
        result.current.reset();
      });

      expect(result.current.isProcessing).toBe(false);
    });

    it('should reset lastExecutionRef to 0', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, { delay: 1000 }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      act(() => {
        jest.advanceTimersByTime(1100);
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(2);

      act(() => {
        result.current.reset();
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(3);
    });

    it('should clear timeout when reset is called', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, { delay: 1000 }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(result.current.isProcessing).toBe(true);

      act(() => {
        result.current.reset();
      });

      expect(result.current.isProcessing).toBe(false);

      act(() => {
        jest.advanceTimersByTime(1100);
      });

      expect(result.current.isProcessing).toBe(false);
    });
  });

  describe('Callback and arguments', () => {
    it('should call callback with correct arguments', async () => {
      const { result } = renderHook(() => usePreventDoubleClick(mockCallback));

      const testArgs = ['arg1', 'arg2', { key: 'value' }];

      await act(async () => {
        await result.current.executeWithPreventDoubleClick(...testArgs);
      });

      expect(mockCallback).toHaveBeenCalledWith(...testArgs);
    });

    it('should handle async callback correctly', async () => {
      const asyncCallback = jest.fn().mockResolvedValue('success');
      const { result } = renderHook(() => usePreventDoubleClick(asyncCallback));

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(asyncCallback).toHaveBeenCalledTimes(1);
    });

    it('should handle sync callback correctly', async () => {
      const syncCallback = jest.fn();
      const { result } = renderHook(() => usePreventDoubleClick(syncCallback));

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(syncCallback).toHaveBeenCalledTimes(1);
    });
  });

  describe('Settings and options', () => {
    it('should use default delay of 1000ms when not specified', async () => {
      const { result } = renderHook(() => usePreventDoubleClick(mockCallback));

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);
    });

    it('should not call onDoubleClickAttempt when not provided', async () => {
      const { result } = renderHook(() => usePreventDoubleClick(mockCallback));

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);
    });

    it('should handle zero delay correctly', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, { delay: 0 }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      expect(mockCallback).toHaveBeenCalledTimes(1);
    });
  });

  describe('Edge cases and error handling', () => {
    it('should handle callback errors gracefully', async () => {
      const errorCallback = jest
        .fn()
        .mockRejectedValue(new Error('Test error'));
      const { result } = renderHook(() => usePreventDoubleClick(errorCallback));

      await act(async () => {
        try {
          await result.current.executeWithPreventDoubleClick();
        } catch (error) {}
      });

      expect(result.current.isProcessing).toBe(true);
    });

    it('should clear previous timeout when new execution starts', async () => {
      const { result } = renderHook(() =>
        usePreventDoubleClick(mockCallback, { delay: 1000 }),
      );

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      act(() => {
        jest.advanceTimersByTime(500);
      });

      await act(async () => {
        await result.current.executeWithPreventDoubleClick();
      });

      act(() => {
        jest.advanceTimersByTime(600);
      });

      expect(result.current.isProcessing).toBe(false);
    });

    it('should handle multiple rapid resets correctly', () => {
      const { result } = renderHook(() => usePreventDoubleClick(mockCallback));

      act(() => {
        result.current.reset();
        result.current.reset();
        result.current.reset();
      });

      expect(result.current.isProcessing).toBe(false);
    });
  });
});

