import { useNavigation } from '@react-navigation/native';
import { renderHook } from '@testing-library/react-hooks';

import { usePrevRoute } from '../../../src/hooks/usePrevRoute';

describe('usePrevRoute Hook', () => {
  it('should return the previous route when there is a navigation history', () => {
    (useNavigation as jest.Mock).mockReturnValue({
      getState: () => ({
        routes: [
          { name: 'Home', params: {} },
          { name: 'Details', params: { id: 1 } },
          { name: 'Profile', params: { user: 'JohnDoe' } },
        ],
      }),
    });

    const { result } = renderHook(() => usePrevRoute());

    expect(result.current).toEqual({ name: 'Details', params: { id: 1 } });
  });

  it('should return undefined when there is no previous route', () => {
    (useNavigation as jest.Mock).mockReturnValue({
      getState: () => ({
        routes: [{ name: 'Home', params: {} }],
      }),
    });

    const { result } = renderHook(() => usePrevRoute());

    expect(result.current).toBeUndefined();
  });

  it('should return undefined when getState returns no routes', () => {
    (useNavigation as jest.Mock).mockReturnValue({
      getState: () => ({
        routes: [],
      }),
    });

    const { result } = renderHook(() => usePrevRoute());

    expect(result.current).toBeUndefined();
  });
});

