import { navigate, navigatorRef } from '../../../src/routes/navigation';

jest.mock('@react-navigation/native', () => ({
  createNavigationContainerRef: jest.fn(() => ({
    isReady: jest.fn(),
    navigate: jest.fn(),
  })),
}));

describe('Navigation Utilities', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should navigate when navigatorRef is ready', () => {
    (navigatorRef.isReady as jest.Mock).mockReturnValue(true);

    const mockName = 'Home' as never;
    const mockParams = { userId: 123 } as never;

    navigate(mockName, mockParams);

    expect(navigatorRef.navigate).toHaveBeenCalledWith(mockName, mockParams);
  });

  it('should not navigate when navigatorRef is not ready', () => {
    (navigatorRef.isReady as jest.Mock).mockReturnValue(false);

    const mockName = 'Profile' as never;
    const mockParams = { userId: 456 } as never;

    navigate(mockName, mockParams);

    expect(navigatorRef.navigate).not.toHaveBeenCalled();
  });
});

